import{_ as a,c as i,o as l,a2 as n}from"./chunks/framework.aRVg8jgk.js";const m=JSON.parse('{"title":"Roadmap","description":"Lynq roadmap: completed milestones in v1.0–v1.1, planned features for v1.2 (PostgreSQL, enhanced observability) and v1.3 (node sharding, advanced multi-tenancy) and beyond.","frontmatter":{"description":"Lynq roadmap: completed milestones in v1.0–v1.1, planned features for v1.2 (PostgreSQL, enhanced observability) and v1.3 (node sharding, advanced multi-tenancy) and beyond."},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md","lastUpdated":1782971053000}'),s={name:"roadmap.md"};function o(t,e,r,c,d,p){return l(),i("div",null,[...e[0]||(e[0]=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /roadmap.md for this page in Markdown format</div><h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>Completed milestones (v1.0, v1.1) and planned features for v1.2 and beyond.</p><h2 id="v1-0-✅" tabindex="-1">v1.0 ✅ <a class="header-anchor" href="#v1-0-✅" aria-label="Permalink to &quot;v1.0 ✅&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Status</p><p>Released</p></div><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ul><li>✅ MySQL datasource support</li><li>✅ Template-based resource generation</li><li>✅ Server-Side Apply (SSA)</li><li>✅ Dependency management with DAG</li><li>✅ Policy-based lifecycle (Creation/Deletion/Conflict)</li><li>✅ Patch strategies (apply/merge/replace)</li><li>✅ Fast reconciliation (30s requeue)</li><li>✅ Smart watch predicates</li><li>✅ Multi-template support</li><li>✅ Webhook validation</li><li>✅ Prometheus metrics</li><li>✅ Grafana dashboard and AlertManager alert rules</li><li>✅ Comprehensive documentation</li></ul><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>✅ Event-driven architecture</li><li>✅ Optimized reconciliation</li><li>✅ Label-based namespace tracking</li><li>✅ Efficient database querying</li></ul><h2 id="v1-1-current-✅" tabindex="-1">v1.1 (Current) ✅ <a class="header-anchor" href="#v1-1-current-✅" aria-label="Permalink to &quot;v1.1 (Current) ✅&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Focus</p><p>Cross-namespace support and operational improvements</p></div><h3 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li><p>✅ <strong>Helm Chart Distribution</strong></p><ul><li>Helm chart published via GitHub Releases</li><li>Public repo: <a href="https://k8s-lynq.github.io/lynq" target="_blank" rel="noreferrer">https://k8s-lynq.github.io/lynq</a></li><li>Customizable values and upgrade path with <code>helm upgrade</code></li></ul></li><li><p>✅ <strong>Cross-Namespace Resource Provisioning</strong></p><ul><li>Support creating node resources in different namespaces using <code>targetNamespace</code> field</li><li>Uses label-based tracking (<code>lynq.sh/node</code>, <code>lynq.sh/node-namespace</code>) for cross-namespace resources</li><li>Automatic detection: same-namespace uses ownerReferences, cross-namespace uses labels</li><li>Dual watch system: <code>Owns()</code> for same-namespace + <code>Watches()</code> with label selectors for cross-namespace</li><li>Enables multi-namespace node isolation and organizational boundaries</li></ul></li><li><p>✅ <strong>Orphan Resource Cleanup</strong></p><ul><li>Automatic detection and cleanup of resources removed from templates</li><li>Status-based tracking with <code>appliedResources</code> field</li><li>Respects DeletionPolicy (Delete/Retain)</li><li>Orphan labels for retained resources for easy identification</li></ul></li><li><p>✅ <strong>Terraform Compatibility</strong> (v1.1.2)</p><ul><li>Immutable <code>hubId</code> enforced via <code>x-kubernetes-validations</code></li><li><code>x-kubernetes-list-type: map</code> on resource arrays enables in-place updates instead of full recreation</li><li><code>DeletionPolicy=Retain</code> resources use label-based tracking; deletion policy evaluated at creation time</li></ul></li><li><p>✅ <strong>Complete Rebrand to Lynq</strong> (v1.1.9)</p><ul><li>Project renamed from tenant-operator to Lynq</li><li>CRDs renamed: TenantRegistry → LynqHub, TenantTemplate → LynqForm, Tenant → LynqNode</li><li>API group migrated to <code>*.lynq.sh</code></li></ul></li><li><p>✅ <strong>Deprecation of <code>.hostOrUrl</code> / <code>.host</code> Variables</strong> (v1.1.11)</p><ul><li>Deprecated in favor of <code>extraValueMappings</code> + <code>toHost()</code> template function</li><li>Scheduled for removal in v1.3.0 (see Breaking Changes below)</li></ul></li><li><p>✅ <strong>Dependency Skip Control and Strict Rendering</strong> (v1.1.14)</p><ul><li><code>skipOnDependencyFailure</code> field controls whether resources are created when dependencies fail</li><li>Strict template rendering surfaces missing-variable errors instead of silently rendering empty values</li><li><code>ignoreFields</code> handling fixes</li></ul></li><li><p>✅ <strong>Gradual Rollout with maxSkew</strong> (v1.1.16)</p><ul><li>Limits concurrent LynqNode updates for safer large-scale rollouts</li><li>Configurable log level with reduced default verbosity</li></ul></li><li><p>✅ <strong>Lynq Dashboard v1.0</strong> (v1.1.17)</p><ul><li>Web UI for visualizing and monitoring operator status</li><li>Topology view of Hub → Form → Node relationships with Problem Mode highlighting</li><li>Overview page, detail pages with conditions/events/YAML, global search</li><li>i18n (English/Korean), dark/light mode, configurable auto-refresh</li></ul></li><li><p>✅ <strong>Performance Optimizations</strong> (v1.1.19)</p><ul><li>Template render cache and SSA apply skip</li><li>Reduced CPU overhead and allocations in reconcile loops</li></ul></li><li><p>✅ <strong>Drift Correction Redesign</strong> (v1.1.20)</p><ul><li>Annotation-driven single skip path: exactly one API write per successful apply</li><li>Periodic force-reapply (~10 min, configurable) as drift-correction backstop for external edits</li><li>maxSkew deadlock fix (readiness timeout measured from apply start time)</li></ul></li></ul><h2 id="v1-2" tabindex="-1">v1.2 <a class="header-anchor" href="#v1-2" aria-label="Permalink to &quot;v1.2&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Focus</p><p>Additional datasources and enhanced observability</p></div><h3 id="new-features-1" tabindex="-1">New Features <a class="header-anchor" href="#new-features-1" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li><p>[ ] <strong>PostgreSQL Datasource</strong></p><ul><li>Full PostgreSQL support</li><li>Connection pooling</li><li>SSL/TLS support</li><li>Query optimization</li></ul></li><li><p>[ ] <strong>Enhanced Metrics Dashboard</strong></p><ul><li>Multi-node metrics visualization</li><li>Performance analytics</li></ul></li></ul><h3 id="improvements" tabindex="-1">Improvements <a class="header-anchor" href="#improvements" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ul><li>[ ] Improved error messages</li><li>[ ] Performance optimizations</li><li>[ ] Extended template functions</li><li>[ ] Better documentation examples</li></ul><h2 id="v1-3" tabindex="-1">v1.3 <a class="header-anchor" href="#v1-3" aria-label="Permalink to &quot;v1.3&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Focus</p><p>Scalability and advanced multi-tenancy features</p></div><h3 id="new-features-2" tabindex="-1">New Features <a class="header-anchor" href="#new-features-2" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li><p>[ ] <strong>Node Sharding for Large-Scale Deployments</strong></p><ul><li>Horizontal sharding of node workloads across multiple operator instances</li><li>Shard key-based node distribution</li><li>Load balancing across shards</li><li>Shard rebalancing and migration support</li><li>Use cases: <ul><li>Supporting 10,000+ nodes per cluster</li><li>Isolating node failures to specific shards</li><li>Reducing controller resource consumption</li><li>Enabling independent scaling of operator replicas</li></ul></li></ul></li><li><p>[ ] <strong>Advanced Multi-Tenancy Isolation</strong></p><ul><li>Node priority and resource quotas</li><li>Per-node rate limiting</li><li>Node lifecycle hooks</li><li>Custom node tagging and filtering</li></ul></li></ul><h3 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Breaking Changes in v1.3.0</p><p>The following deprecated features will be <strong>removed</strong> in v1.3.0:</p></div><ul><li>[ ] <strong>Removal of Deprecated <code>.hostOrUrl</code> and <code>.host</code> Variables</strong><ul><li><strong>Deprecated since</strong>: v1.1.11</li><li><strong>Removed in</strong>: v1.3.0</li><li><strong>Migration required</strong>: Use <code>extraValueMappings</code> + <code>toHost()</code> template function</li><li><strong>Impact</strong>: LynqHub configurations using <code>valueMappings.hostOrUrl</code> will fail validation</li><li><strong>Migration guide</strong>:<div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Before (deprecated - will fail in v1.3.0)</span></span>
<span class="line"><span style="color:#85E89D;">valueMappings</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  uid</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">node_id</span></span>
<span class="line"><span style="color:#85E89D;">  hostOrUrl</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">domain_url</span><span style="color:#6A737D;">  # ❌ Removed</span></span>
<span class="line"><span style="color:#85E89D;">  activate</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">is_active</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># After (v1.3.0+)</span></span>
<span class="line"><span style="color:#85E89D;">valueMappings</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  uid</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">node_id</span></span>
<span class="line"><span style="color:#85E89D;">  activate</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">is_active</span></span>
<span class="line"><span style="color:#85E89D;">extraValueMappings</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  nodeUrl</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">domain_url</span><span style="color:#6A737D;">    # ✅ Use extraValueMappings</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># In templates: {{ .nodeUrl | toHost }}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div></li><li><strong>Rationale</strong>: Lynq is a general database-driven automation platform; removing the hardcoded host/URL requirement provides flexibility for diverse use cases beyond web-hosting scenarios</li></ul></li></ul><h3 id="improvements-1" tabindex="-1">Improvements <a class="header-anchor" href="#improvements-1" aria-label="Permalink to &quot;Improvements&quot;">​</a></h3><ul><li>[ ] Enhanced reconciliation performance for large node counts</li><li>[ ] Improved status reporting and aggregation</li><li>[ ] Optimized database query batching</li><li>[ ] Better scaling metrics and recommendations</li></ul><h2 id="contributing-to-roadmap" tabindex="-1">Contributing to Roadmap <a class="header-anchor" href="#contributing-to-roadmap" aria-label="Permalink to &quot;Contributing to Roadmap&quot;">​</a></h2><p>Want to influence the roadmap?</p><ol><li><strong>Open a Discussion</strong>: Share your use case</li><li><strong>Vote on Features</strong>: Upvote existing requests</li><li><strong>Submit PRs</strong>: Implement features yourself</li><li><strong>Join Community</strong>: Participate in discussions</li></ol><h2 id="stability-commitments" tabindex="-1">Stability Commitments <a class="header-anchor" href="#stability-commitments" aria-label="Permalink to &quot;Stability Commitments&quot;">​</a></h2><h3 id="api-stability" tabindex="-1">API Stability <a class="header-anchor" href="#api-stability" aria-label="Permalink to &quot;API Stability&quot;">​</a></h3><ul><li>v1 API: Stable, no breaking changes</li><li>Future versions: Migration guides provided</li><li>Deprecation policy: 6 months notice</li></ul><h3 id="backwards-compatibility" tabindex="-1">Backwards Compatibility <a class="header-anchor" href="#backwards-compatibility" aria-label="Permalink to &quot;Backwards Compatibility&quot;">​</a></h3><ul><li>Database schema changes: Automatic migration</li><li>Template syntax: Backwards compatible</li><li>Metrics: No breaking changes without notice</li></ul><h2 id="getting-involved" tabindex="-1">Getting Involved <a class="header-anchor" href="#getting-involved" aria-label="Permalink to &quot;Getting Involved&quot;">​</a></h2><ul><li>💬 Discussions: <a href="https://github.com/k8s-lynq/lynq/discussions" target="_blank" rel="noreferrer">https://github.com/k8s-lynq/lynq/discussions</a></li><li>🐛 Issues: <a href="https://github.com/k8s-lynq/lynq/issues" target="_blank" rel="noreferrer">https://github.com/k8s-lynq/lynq/issues</a></li><li>📧 Email: <a href="mailto:rationlunas@gmail.com" target="_blank" rel="noreferrer">rationlunas@gmail.com</a></li><li>🔔 Release notifications: Watch repository</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="https://github.com/k8s-lynq/lynq/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">Contributing Guide</a></li><li><a href="./development">Development Guide</a></li><li><a href="https://github.com/k8s-lynq/lynq/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a></li></ul>`,40)])])}const h=a(s,[["render",o]]);export{m as __pageData,h as default};
